python3 << 'EOF'
import re

def find_functions_with_pattern(filepath, pattern):
    try:
        with open(filepath, 'r') as f:
            lines = f.readlines()
    except FileNotFoundError:
        return []

    results = []
    current_func = None
    current_func_line = 0

    for i, line in enumerate(lines, 1):
        if line.strip().startswith('func '):
            # Extract function name
            match = re.search(r'func\s+(?:\(([^)]*)\)\s+)?(\w+)\(', line)
            if match:
                receiver = match.group(1)
                fname = match.group(2)
                if receiver:
                    # Extract type from receiver
                    type_match = re.search(r'\*?(\w+)', receiver)
                    if type_match:
                        current_func = f"{type_match.group(1)}.{fname}"
                else:
                    current_func = fname
                current_func_line = i

        if pattern in line and current_func:
            results.append((filepath, i, current_func, current_func_line))

    return results

files = [
    'staging/src/k8s.io/client-go/informers/generic.go',
    'staging/src/k8s.io/client-go/kubernetes_test/clientset_test.go',
    'staging/src/k8s.io/sample-controller/controller_test.go',
    'staging/src/k8s.io/sample-controller/main.go'
]

pattern = "Apps().V1().Deployments()"

for filepath in files:
    results = find_functions_with_pattern(filepath, pattern)
    for file, line, func, func_line in results:
        print(f"{file}:{line} in {func}")
EOF

